"export interface ResolvedEntity {
  name: string;
  ticker?: string;
  isPublic: boolean;
}

export interface NewsResearch {
  summary: string;
  sentiment: "positive" | "neutral" | "negative";
  sources: string[];
}

export interface FinancialData {
  summary: string;
  metrics: Record<string, string | number>;
  sources: string[];
}

export interface CompetitiveLandscape {
  summary: string;
  competitors: string[];
  sources: string[];
}

export interface RiskFactors {
  summary: string;
  risks: string[];
  sources: string[];
}

export interface DecisionResult {
  decision: "INVEST" | "PASS" | null;
  confidence: number | null;
  keyPositives: string[];
  keyRisks: string[];
  reasoning: string | null;
  oneLineVerdict?: string;
}

export interface AgentStateData {
  companyName: string;
  resolved: boolean;
  resolvedEntity: ResolvedEntity | null;
  newsResearch: NewsResearch | null;
  financialData: FinancialData | null;
  competitiveLandscape: CompetitiveLandscape | null;
  riskFactors: RiskFactors | null;
  synthesizedBrief: string | null;
  decision: "INVEST" | "PASS" | null;
  confidence: number | null;
  keyPositives: string[];
  keyRisks: string[];
  reasoning: string | null;
  finalReport: string | null;
  errors: string[];
}

export interface SSEEvent {
  node: string;
  message: string;
}
"

"import { z } from "zod";

export const ResolveCompanySchema = z.object({
  resolved: z.boolean(),
  name: z.string(),
  ticker: z.string().nullable().optional(),
  isPublic: z.boolean(),
});

export const DecisionOutputSchema = z.object({
  decision: z.enum(["INVEST", "PASS"]),
  confidence: z.number().min(0).max(100),
  oneLineVerdict: z.string(),
  keyPositives: z.array(z.string()).min(2).max(5),
  keyRisks: z.array(z.string()).min(2).max(5),
  reasoning: z.string(),
});
"

"import { ChatOpenAI } from "@langchain/openai";
import { ChatAnthropic } from "@langchain/anthropic";
import { BaseChatModel } from "@langchain/core/language_models/chat_models";

export function getLLM(): BaseChatModel {
  const provider = process.env.LLM_PROVIDER || "openai";
  const modelName = process.env.MODEL_NAME;

  if (provider === "openai") {
    const apiKey = process.env.OPENAI_API_KEY;
    if (!apiKey) {
      throw new Error("Missing OPENAI_API_KEY in environment variables.");
    }
    return new ChatOpenAI({
      openAIApiKey: apiKey,
      modelName: modelName || "gpt-4o-mini",
      temperature: 0.1,
    });
  } else if (provider === "anthropic") {
    const apiKey = process.env.ANTHROPIC_API_KEY;
    if (!apiKey) {
      throw new Error("Missing ANTHROPIC_API_KEY in environment variables.");
    }
    return new ChatAnthropic({
      apiKey: apiKey,
      modelName: modelName || "claude-3-5-sonnet-20241022",
      temperature: 0.1,
    });
  } else {
    throw new Error(`Unsupported LLM_PROVIDER: "${provider}". Must be "openai" or "anthropic".`);
  }
}
"

"export interface SearchResult {
  title: string;
  url: string;
  content: string;
  score: number;
}

export interface SearchResponse {
  results: SearchResult[];
}

export async function searchWeb(query: string, maxResults = 5): Promise<SearchResponse> {
  const apiKey = process.env.TAVILY_API_KEY;
  if (!apiKey) {
    throw new Error("Missing TAVILY_API_KEY environment variable.");
  }

  try {
    const response = await fetch("https://api.tavily.com/search", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        api_key: apiKey,
        query: query,
        max_results: maxResults,
        include_answer: false,
      }),
    });

    if (!response.ok) {
      const errorText = await response.text();
      throw new Error(`Tavily search API failed: ${response.statusText} - ${errorText}`);
    }

    const data = (await response.json()) as SearchResponse;
    return data;
  } catch (error: any) {
    console.error("Error in searchWeb tool:", error);
    throw error;
  }
}
"

