"import { Annotation } from "@langchain/langgraph";
import { 
  ResolvedEntity, 
  NewsResearch, 
  FinancialData, 
  CompetitiveLandscape, 
  RiskFactors 
} from "../../types";

export const AgentState = Annotation.Root({
  companyName: Annotation<string>,
  resolved: Annotation<boolean>,
  resolvedEntity: Annotation<ResolvedEntity | null>,

  newsResearch: Annotation<NewsResearch | null>,
  financialData: Annotation<FinancialData | null>,
  competitiveLandscape: Annotation<CompetitiveLandscape | null>,
  riskFactors: Annotation<RiskFactors | null>,

  synthesizedBrief: Annotation<string | null>,

  decision: Annotation<"INVEST" | "PASS" | null>,
  confidence: Annotation<number | null>,        // 0-100
  keyPositives: Annotation<string[]>,
  keyRisks: Annotation<string[]>,
  reasoning: Annotation<string | null>,

  finalReport: Annotation<string | null>,        // full markdown, what the UI renders
  errors: Annotation<string[]>({
    reducer: (existing, update) => existing.concat(update),
    default: () => [],
  }),
});
