"import { getLLM } from "../../llm";
import { AgentState } from "../state";
import { ResolveCompanySchema } from "../schemas";
import { RESOLVE_COMPANY_PROMPT } from "../prompts";

/**
 * resolveCompany node:
 * Uses the LLM to normalize the user's company input, verify it's a real entity,
 * and extract a stock ticker (if applicable) and whether it's public.
 */
export async function resolveCompany(state: typeof AgentState.State): Promise<Partial<typeof AgentState.State>> {
  console.log(`[resolveCompany] Resolving input: "${state.companyName}"`);
  try {
    const llm = getLLM();
    // Using structured output to ensure response matches schema exactly
    const structuredLlm = llm.withStructuredOutput(ResolveCompanySchema);

    const prompt = RESOLVE_COMPANY_PROMPT.replace("{companyName}", state.companyName);

    const result = await structuredLlm.invoke(prompt);

    if (!result || !result.resolved) {
      console.log(`[resolveCompany] Could not resolve entity for: "${state.companyName}"`);
      return {
        resolved: false,
        resolvedEntity: null,
      };
    }

    console.log(`[resolveCompany] Resolved: ${result.name} (Ticker: ${result.ticker || "N/A"}, Public: ${result.isPublic})`);
    return {
      resolved: true,
      resolvedEntity: {
        name: result.name,
        ticker: result.ticker || undefined,
        isPublic: result.isPublic,
      },
    };
  } catch (error: any) {
    console.error("[resolveCompany] Error resolving company:", error);
    return {
      resolved: false,
      resolvedEntity: null,
      errors: [`Failed to resolve company "${state.companyName}": ${error.message || error}`],
    };
  }
}
"

"import { getLLM } from "../../llm";
import { AgentState } from "../state";
import { searchWeb } from "../../tools/webSearch";
import { NEWS_RESEARCH_PROMPT } from "../prompts";
import { z } from "zod";

const NewsSentimentSchema = z.object({
  summary: z.string(),
  sentiment: z.enum(["positive", "neutral", "negative"]),
  sources: z.array(z.string()),
});

/**
 * gatherNews node:
 * Searches the web for recent news and sentiment signals about the company,
 * and synthesizes a summary and sentiment score.
 */
export async function gatherNews(state: typeof AgentState.State): Promise<Partial<typeof AgentState.State>> {
  const entity = state.resolvedEntity;
  if (!entity) {
    return { newsResearch: null };
  }

  console.log(`[gatherNews] Researching news for: ${entity.name}`);
  try {
    const query = `${entity.name} recent news business sentiment stock performance 2026`;
    const searchRes = await searchWeb(query, 5);

    const searchResultsString = searchRes.results
      .map((r) => `Title: ${r.title}\nURL: ${r.url}\nContent: ${r.content}\n---`)
      .join("\n");

    const llm = getLLM().withStructuredOutput(NewsSentimentSchema);

    const prompt = NEWS_RESEARCH_PROMPT
      .replace("{companyName}", entity.name)
      .replace("{searchResults}", searchResultsString);

    const response = await llm.invoke(prompt);

    return {
      newsResearch: {
        summary: response.summary,
        sentiment: response.sentiment,
        sources: response.sources.length > 0 ? response.sources : searchRes.results.map((r) => r.url),
      },
    };
  } catch (error: any) {
    console.error("[gatherNews] Error gathering news:", error);
    return {
      newsResearch: null,
      errors: [`Failed to gather news research for ${entity.name}: ${error.message || error}`],
    };
  }
}
"

