"import { getLLM } from "../../llm";
import { AgentState } from "../state";
import { DecisionOutputSchema } from "../schemas";
import { DECIDE_PROMPT } from "../prompts";

/**
 * decide node:
 * Takes the synthesized brief and prompts the LLM to make a structured investment
 * decision (INVEST/PASS, confidence, key reasons, risks, and reasoning).
 */
export async function decide(state: typeof AgentState.State): Promise<Partial<typeof AgentState.State>> {
  const entity = state.resolvedEntity;
  if (!entity || !state.synthesizedBrief) {
    return {
      decision: null,
      confidence: null,
      oneLineVerdict: null,
      keyPositives: [],
      keyRisks: [],
      reasoning: null,
    };
  }

  console.log(`[decide] Formulating investment decision for: ${entity.name}`);

  try {
    const llm = getLLM().withStructuredOutput(DecisionOutputSchema);

    const prompt = DECIDE_PROMPT
      .replace("{companyName}", entity.name)
      .replace("{brief}", state.synthesizedBrief);

    const result = await llm.invoke(prompt);

    console.log(`[decide] Decision formulated: ${result.decision} with ${result.confidence}% confidence.`);

    return {
      decision: result.decision,
      confidence: result.confidence,
      oneLineVerdict: result.oneLineVerdict,
      keyPositives: result.keyPositives,
      keyRisks: result.keyRisks,
      reasoning: result.reasoning,
    };
  } catch (error: any) {
    console.error("[decide] Error making decision:", error);
    return {
      decision: "PASS",
      confidence: 10,
      oneLineVerdict: "Error in decision process.",
      keyPositives: ["Data collection succeeded"],
      keyRisks: ["System processing errors"],
      reasoning: `An error occurred while compiling the investment decision: ${error.message || error}`,
      errors: [`Decision node failed: ${error.message || error}`],
    };
  }
}
"

